echo eyJhY3Rpb25fZDc1YmZiOWUiOiAwLjA2LCAiYWN0aW9uX2RlOTY0YTczIjogMC4xMiwgImFjdGlvbl82ZWEzMzZmOCI6IDAuMSwgImFjdGlvbl85YzIyZWEyMiI6IDAuM30K | base64 -d | redis-cli -x set nba:sim:propensity >/dev/null
